#include<bits/stdc++.h>
using namespace std;
#define int long long

const int N = 1e5 + 5;

int st1[N], top1, st2[N], top2, a[N], l[N], r[N], sum[N];

signed main()
{
	int n, ans = 0;
	cin >> n;
	for(int i = 1; i <= n; i++)
	{
		cin >> a[i];
		sum[i] = sum[i - 1] + a[i];
	}
	for(int i = 1; i <= n; i++)
	{
		while(top1 > 0 && a[st1[top1]] >= a[i])
			top1--;
		l[i] = st1[top1];
		st1[++top1] = i;
	}
	st2[0] = n + 1;
	for(int i = n; i >= 1; i--)
	{
		while(top2 > 0 && a[st2[top2]] >= a[i])
			top2--;
		r[i] = st2[top2] - 1;
		st2[++top2] = i;
	}
	for(int i = 1; i <= n; i++)
		ans = max(ans, a[i] * (sum[r[i]] - sum[l[i]]));
	cout << ans;
}
